!function(){"use strict";window.Plugins=window.Plugins||{},window.Plugins.GlobalState=class{static _state={};static _listeners={};static _events={};static set(t,s){this._state[t]=s,this._listeners[t]&&this._listeners[t].forEach(t=>t(s)),document.dispatchEvent(new CustomEvent("changed.plugin.globalState",{detail:{key:t,value:s}}))}static get(t){return this._state[t]}static subscribe(t,s){this._listeners[t]||(this._listeners[t]=[]),this._listeners[t].push(s)}static unsubscribe(t,s){this._listeners[t]&&(this._listeners[t]=this._listeners[t].filter(t=>t!==s))}static publish(t,s){this._events[t]&&this._events[t].forEach(t=>t(s))}static on(t,s){this._events[t]||(this._events[t]=[]),this._events[t].push(s)}static off(t,s){this._events[t]&&(this._events[t]=this._events[t].filter(t=>t!==s))}static clear(){for(const t in this._state)delete this._state[t];for(const t in this._listeners)delete this._listeners[t];for(const t in this._events)delete this._events[t]}}}();